+function resolveSessionEntryForKey(
+  store: Record<string, { sessionId: string; updatedAt: number }> | undefined,
+  sessionKey: string | undefined,
+) {
+  if (!store || !sessionKey) return {};
+  const direct = store[sessionKey];
